INSERT INTO public.posts (title, title_en, content, excerpt, category, tags, published, featured) VALUES
('ফরিদপুরের ইতিহাস ও ঐতিহ্য', 'History and Heritage of Faridpur', 'ফরিদপুর বাংলাদেশের একটি ঐতিহ্যবাহী জেলা। এর সমৃদ্ধ সাংস্কৃতিক ইতিহাস রয়েছে যা শতাব্দীর পর শতাব্দী ধরে গড়ে উঠেছে। পদ্মা নদীর তীরে অবস্থিত এই জেলা তার সাহিত্য, সংস্কৃতি ও কৃষিতে সমৃদ্ধ।', 'ফরিদপুরের সমৃদ্ধ ইতিহাস ও সাংস্কৃতিক ঐতিহ্যের পরিচয়।', 'ইতিহাস', ARRAY['ফরিদপুর','ইতিহাস','ঐতিহ্য'], true, true),
('বাংলা কবিতার আধুনিক ধারা', 'Modern Trends in Bengali Poetry', 'আধুনিক বাংলা কবিতা নানা পরীক্ষা-নিরীক্ষার মধ্য দিয়ে এগিয়ে চলেছে। তরুণ কবিরা নতুন ভাষা ও প্রকরণে কবিতা লিখছেন।', 'বাংলা কবিতার নতুন দিগন্ত ও আধুনিক কবিদের পরীক্ষা-নিরীক্ষা।', 'সাহিত্য', ARRAY['কবিতা','সাহিত্য','আধুনিক'], true, false),
('সাহিত্য পরিষদের বার্ষিক সম্মেলন ২০২৬', 'Annual Literary Conference 2026', 'ফরিদপুর সাহিত্য পরিষদের বার্ষিক সম্মেলন আগামী মাসে অনুষ্ঠিত হতে যাচ্ছে। এবারের সম্মেলনে বিশেষ অতিথি হিসেবে থাকবেন বিশিষ্ট সাহিত্যিকগণ।', 'বার্ষিক সম্মেলনের বিস্তারিত তথ্য ও কার্যসূচি।', 'সংবাদ', ARRAY['সম্মেলন','পরিষদ','২০২৬'], true, false);
INSERT INTO public.events (title, title_en, date, time, location, description, tag, tag_color) VALUES
('বার্ষিক সাহিত্য উৎসব ২০২৬', 'Annual Literary Festival 2026', '২০২৬-০৫-১৫', 'সকাল ১০:০০', 'ফরিদপুর টাউন হল', 'ফরিদপুর সাহিত্য পরিষদের বার্ষিক সাহিত্য উৎসব। কবিতা পাঠ, গল্প পাঠ, ও সাহিত্য আলোচনা।', 'সাহিত্য', 'bg-primary text-primary-foreground'),
('কবিতা সন্ধ্যা', 'Poetry Evening', '২০২৬-০৪-২০', 'বিকাল ৫:০০', 'পদ্মা পাড় মঞ্চ', 'তরুণ কবিদের কবিতা পাঠের আসর। নতুন কবিতা উপস্থাপন ও আলোচনা।', 'কবিতা', 'bg-accent text-accent-foreground'),
('বইমেলা ২০২৬', 'Book Fair 2026', '২০২৬-০৬-০১', 'সকাল ৯:০০ - রাত ৯:০০', 'ফরিদপুর শিল্পকলা একাডেমি', 'স্থানীয় লেখকদের বই প্রদর্শনী ও বিক্রয়। বিশেষ ছাড়ে বই কেনার সুযোগ।', 'বইমেলা', 'bg-primary text-primary-foreground');